#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int dp[100005][1000005];

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int restrictions[M][3];
        for (int i = 0; i < M; i++) {
            char type;
            int L, R;
            scanf(" %c %d %d", &type, &L, &R);
            restrictions[i][0] = type == 'I';
            restrictions[i][1] = L;
            restrictions[i][2] = R;
        }
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= K; j++) {
                if (dp[i][j] == 0) continue;
                if (A[i] != -1 && A[i] != j) continue;
                if (i == 0 || A[i-1] == -1 || A[i-1] == j-1) {
                    dp[i+1][j+1] = (dp[i+1][j+1] + dp[i][j]) % MOD;
                }
                if (i == 0 || A[i-1] == -1 || A[i-1] == j+1) {
                    dp[i+1][j-1] = (dp[i+1][j-1] + dp[i][j]) % MOD;
                }
                for (int k = 0; k < M; k++) {
                    if (restrictions[k][0] && restrictions[k][1] <= i+1 && i+1 <= restrictions[k][2]) {
                        if (j != K && dp[i+1][j+1] != 0) {
                            dp[i+1][j+1] = (dp[i+1][j+1] + dp[i][j]) % MOD;
                        }
                    } else if (!restrictions[k][0] && restrictions[k][1] <= i+1 && i+1 <= restrictions[k][2]) {
                        if (j != 1 && dp[i+1][j-1] != 0) {
                            dp[i+1][j-1] = (dp[i+1][j-1] + dp[i][j]) % MOD;
                        }
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 1; i <= K; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

