const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function nextLine() {
    return input[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

for (let t = nextInt(); t > 0; t--) {
    let [N, M, K] = nextInts();
    let A = nextInts();
    let restrictions = [];
    for (let i = 0; i < M; i++) {
        let [type, L, R] = nextLine().split(' ');
        L = parseInt(L);
        R = parseInt(R);
        restrictions.push([type === 'I', L, R]);
    }
    let dp = Array(N + 1).fill(0).map(() => Array(K + 1).fill(0));
    dp[0][0] = 1;
    for (let i = 0; i < N; i++) {
        for (let j = 0; j <= K; j++) {
            if (dp[i][j] === 0) continue;
            if (A[i] !== -1 && A[i] !== j) continue;
            if (i === 0 || A[i-1] === -1 || A[i-1] === j-1) {
                dp[i+1][j+1] = (dp[i+1][j+1] + dp[i][j]) % MOD;
            }
            if (i === 0 || A[i-1] === -1 || A[i-1] === j+1) {
                dp[i+1][j-1] = (dp[i+1][j-1] + dp[i][j]) % MOD;
            }
            for (let [type, L, R] of restrictions) {
                if (type && L <= i+1 && i+1 <= R) {
                    if (j !== K && dp[i+1][j+1] !== 0) {
                        dp[i+1][j+1] = (dp[i+1][j+1] + dp[i][j]) % MOD;
                    }
                } else if (!type && L <= i+1 && i+1 <= R) {
                    if (j !== 1 && dp[i+1][j-1] !== 0) {
                        dp[i+1][j-1] = (dp[i+1][j-1] + dp[i][j]) % MOD;
                    }
                }
            }
        }
    }
    let ans = 0;
    for (let i = 1; i <= K; i++) {
